"""DeepLake Managed Service Client.

Provides a unified interface for:
1. Token-based authentication (org_id always extracted from token)
2. Dataset creation at root_path/workspace_id/table_name (root_path from API)
3. File ingestion with chunking
4. Automatic table creation via API (POST /workspaces/{id}/tables)
5. Fluent query API: client.db.query("table").select(...).where(...)

All database operations go through the REST API — no direct PG connection needed.
"""

from __future__ import annotations

import base64
import json
import logging
import os
from pathlib import Path
from typing import Any, Callable, Dict, List, Optional, Tuple
from urllib.parse import urljoin

import requests

from .errors import (
    AuthError,
    CredentialsError,
    IngestError,
    ManagedServiceError,
    TableError,
    TokenError,
    WorkspaceError,
)

logger = logging.getLogger(__name__)

DEFAULT_API_URL = "https://api.deeplake.ai"

_VIDEO_EXTS = {".mp4", ".mov", ".avi", ".mkv", ".webm"}
_IMAGE_EXTS = {".jpg", ".jpeg", ".png", ".gif", ".bmp", ".webp"}
_TEXT_EXTS = {".txt", ".md", ".json", ".csv", ".xml", ".html"}


class ManagedDataset:
    """Thin wrapper around ``deeplake.Dataset`` that auto-refreshes before queries.

    Managed datasets are opened at a point-in-time snapshot.  Without an
    explicit ``refresh()`` call, queries won't see data committed by other
    writers (e.g. a separate ``Client.ingest()`` call).  This wrapper calls
    ``refresh()`` automatically before ``query()`` — matching the behaviour
    of pg_deeplake where every scan starts with a refresh.

    All other attribute access is forwarded to the underlying dataset.
    """

    def __init__(self, ds: Any) -> None:
        self._ds = ds

    # -- query methods (auto-refresh before execution) --

    def query(self, query: str) -> Any:
        self._ds.refresh()
        return self._ds.query(query)

    def query_async(self, query: str) -> Any:
        self._ds.refresh()
        return self._ds.query_async(query)

    def prepare_query(self, query: str) -> Any:
        self._ds.refresh()
        return self._ds.prepare_query(query)

    def explain_query(self, query: str) -> Any:
        self._ds.refresh()
        return self._ds.explain_query(query)

    # -- snapshot control --

    def refresh(self) -> None:
        self._ds.refresh()

    def refresh_async(self) -> Any:
        return self._ds.refresh_async()

    # -- schema & metadata --

    @property
    def schema(self) -> Any:
        return self._ds.schema

    @property
    def version(self) -> str:
        return self._ds.version

    @property
    def name(self) -> str:
        return self._ds.name

    @property
    def id(self) -> str:
        return self._ds.id

    @property
    def description(self) -> Any:
        return self._ds.description

    @property
    def metadata(self) -> Any:
        return self._ds.metadata

    @property
    def created_time(self) -> Any:
        return self._ds.created_time

    @property
    def query_config(self) -> Any:
        return self._ds.query_config

    @property
    def indexing_config(self) -> Any:
        return self._ds.indexing_config

    @property
    def indexing_mode(self) -> Any:
        return self._ds.indexing_mode

    @property
    def auto_commit_enabled(self) -> bool:
        return self._ds.auto_commit_enabled

    @property
    def logging_enabled(self) -> bool:
        return self._ds.logging_enabled

    @property
    def compaction_mode(self) -> Any:
        return self._ds.compaction_mode

    @property
    def current_branch(self) -> str:
        return self._ds.current_branch

    @property
    def branches(self) -> Any:
        return self._ds.branches

    @property
    def tags(self) -> Any:
        return self._ds.tags

    @property
    def history(self) -> Any:
        return self._ds.history

    @property
    def creds_key(self) -> Any:
        return self._ds.creds_key

    # -- mutating operations --

    def add_column(self, *args: Any, **kwargs: Any) -> None:
        self._ds.add_column(*args, **kwargs)

    def remove_column(self, *args: Any, **kwargs: Any) -> None:
        self._ds.remove_column(*args, **kwargs)

    def rename_column(self, *args: Any, **kwargs: Any) -> None:
        self._ds.rename_column(*args, **kwargs)

    def append(self, *args: Any, **kwargs: Any) -> None:
        self._ds.append(*args, **kwargs)

    def delete(self, *args: Any, **kwargs: Any) -> None:
        self._ds.delete(*args, **kwargs)

    def commit(self, *args: Any, **kwargs: Any) -> None:
        self._ds.commit(*args, **kwargs)

    def commit_async(self, *args: Any, **kwargs: Any) -> Any:
        return self._ds.commit_async(*args, **kwargs)

    def rollback(self, *args: Any, **kwargs: Any) -> None:
        self._ds.rollback(*args, **kwargs)

    def rollback_async(self, *args: Any, **kwargs: Any) -> Any:
        return self._ds.rollback_async(*args, **kwargs)

    def merge(self, *args: Any, **kwargs: Any) -> None:
        self._ds.merge(*args, **kwargs)

    def compact(self, *args: Any, **kwargs: Any) -> None:
        self._ds.compact(*args, **kwargs)

    def compact_async(self, *args: Any, **kwargs: Any) -> Any:
        return self._ds.compact_async(*args, **kwargs)

    def push(self, *args: Any, **kwargs: Any) -> None:
        self._ds.push(*args, **kwargs)

    def push_async(self, *args: Any, **kwargs: Any) -> Any:
        return self._ds.push_async(*args, **kwargs)

    def pull(self, *args: Any, **kwargs: Any) -> None:
        self._ds.pull(*args, **kwargs)

    def pull_async(self, *args: Any, **kwargs: Any) -> Any:
        return self._ds.pull_async(*args, **kwargs)

    def build_indexes(self, *args: Any, **kwargs: Any) -> None:
        self._ds.build_indexes(*args, **kwargs)

    def build_indexes_async(self, *args: Any, **kwargs: Any) -> Any:
        return self._ds.build_indexes_async(*args, **kwargs)

    def tag(self, *args: Any, **kwargs: Any) -> Any:
        return self._ds.tag(*args, **kwargs)

    def set_creds_key(self, *args: Any, **kwargs: Any) -> None:
        self._ds.set_creds_key(*args, **kwargs)

    def start_logging(self, *args: Any, **kwargs: Any) -> None:
        self._ds.start_logging(*args, **kwargs)

    def stop_logging(self, *args: Any, **kwargs: Any) -> None:
        self._ds.stop_logging(*args, **kwargs)

    # -- data access --

    def summary(self) -> None:
        self._ds.summary()

    def to_csv(self, stream: Any) -> None:
        self._ds.to_csv(stream)

    def pytorch(self, *args: Any, **kwargs: Any) -> Any:
        return self._ds.pytorch(*args, **kwargs)

    def tensorflow(self) -> Any:
        return self._ds.tensorflow()

    def batches(self, batch_size: int, drop_last: bool = False) -> Any:
        return self._ds.batches(batch_size, drop_last)

    # -- dunder methods --

    def __getitem__(self, key: Any) -> Any:
        return self._ds[key]

    def __len__(self) -> int:
        return len(self._ds)

    def __iter__(self) -> Any:
        return iter(self._ds)

    def __str__(self) -> str:
        return str(self._ds)

    def __repr__(self) -> str:
        return repr(self._ds)

    def __getattr__(self, name: str) -> Any:
        return getattr(self._ds, name)


class Client:
    """DeepLake Managed Service Client.

    Provides agent-friendly interface for data ingestion and querying.
    All database operations use the REST API — no direct PG connection.

    Args:
        token: API token.  Falls back to the ``DEEPLAKE_API_KEY``
            environment variable when not provided explicitly.
        workspace_id: Target workspace identifier (default: ``"default"``).
        api_url: API base URL (default: https://api.deeplake.ai).

    Example:
        >>> client = Client()  # uses DEEPLAKE_API_KEY env var + "default" workspace
        >>> client = Client(token="dl_xxx", workspace_id="my-workspace")
        >>> client.ingest("videos", {"path": ["video1.mp4"]}, schema={"path": "FILE"})
        >>> results = client.table("videos").select("id", "text").limit(10)()
    """

    def __init__(
        self,
        token: Optional[str] = None,
        workspace_id: str = "default",
        api_url: Optional[str] = None,
    ):
        token = token or os.environ.get("DEEPLAKE_API_KEY")
        if not token:
            raise AuthError(
                "API key required. Pass token= to Client() or set the "
                "DEEPLAKE_API_KEY environment variable."
            )
        self.token = token

        self.workspace_id = workspace_id

        self.api_url = (api_url or DEFAULT_API_URL).rstrip("/")

        # Initialize org_id to None before _extract_org_id so that
        # _api_request (called by _fetch_org_id_from_api) can safely
        # check ``self.org_id`` without raising AttributeError.
        self.org_id: Optional[str] = None

        # Always extract org_id from token
        self.org_id = self._extract_org_id(self.token)

        # Cached root path
        self._root_path: Optional[str] = None

        # Lock for thread-safe access to global deeplake.client.endpoint
        # and the C++ dataset operations (open/append/commit).
        import threading
        self._deeplake_lock = threading.Lock()

        logger.info(
            "Client initialized: org_id=%s, workspace_id=%s",
            self.org_id,
            self.workspace_id,
        )

    def close(self):
        """Close the client and release resources.

        The sync client is stateless (each HTTP request uses a fresh
        connection), so this is a no-op.  Provided so that callers can
        use a uniform ``client.close()`` pattern regardless of client type.
        """
        pass

    def __enter__(self):
        return self

    def __exit__(self, *exc):
        self.close()

    def table(self, table_name: str) -> "ManagedQueryBuilder":
        """Start building a fluent query against the given table.

        Returns a chainable :class:`ManagedQueryBuilder`.

        Example:
            >>> results = client.table("videos").select("id", "text").limit(10)()
        """
        return ManagedQueryBuilder(self, table_name)


    def _extract_org_id(self, token: str) -> str:
        """Extract org_id from API token claims.

        API tokens are HMAC-SHA256 signed JWTs with structure:
        header.payload.signature

        Payload contains: Type, Name, UserID, OrgID, Exp, Iat
        """
        try:
            parts = token.split(".")
            if len(parts) != 3:
                raise TokenError("Invalid token format: expected JWT with 3 parts")

            # Decode payload (base64url)
            payload = parts[1]
            # Add padding if needed
            padding = 4 - len(payload) % 4
            if padding != 4:
                payload += "=" * padding

            decoded = base64.urlsafe_b64decode(payload)
            claims = json.loads(decoded)

            org_id = claims.get("OrgID") or claims.get("org_id")
            if not org_id:
                # Try to get from API if not in token
                org_id = self._fetch_org_id_from_api()

            if not org_id:
                raise TokenError("Token does not contain org_id claim")

            return org_id

        except json.JSONDecodeError as e:
            raise TokenError(f"Failed to decode token payload: {e}") from e
        except Exception as e:
            if isinstance(e, TokenError):
                raise
            raise TokenError(f"Failed to extract org_id from token: {e}") from e

    def _fetch_org_id_from_api(self) -> Optional[str]:
        """Fetch org_id from API using token."""
        try:
            resp = self._api_request("GET", "/me")
            # /me returns {"organizations": ["uuid1", ...], ...}
            orgs = resp.get("organizations")
            if orgs and len(orgs) > 0:
                return str(orgs[0])
            return None
        except Exception:
            return None

    def _api_request(
        self,
        method: str,
        path: str,
        json_data: Optional[Dict] = None,
        params: Optional[Dict] = None,
        timeout: int = 30,
    ) -> Dict[str, Any]:
        """Make authenticated API request."""
        import json as json_mod
        from urllib.request import Request, urlopen
        from urllib.error import HTTPError, URLError
        from urllib.parse import urlencode

        url = urljoin(self.api_url, path)
        if params:
            url = f"{url}?{urlencode(params)}"

        headers = {
            "Authorization": f"Bearer {self.token}",
            "Content-Type": "application/json",
            "X-Deeplake-Client": "python-sdk",
        }
        if self.org_id:
            headers["X-Activeloop-Org-Id"] = self.org_id

        body = json_mod.dumps(json_data).encode() if json_data else None
        req = Request(url, data=body, headers=headers, method=method)

        try:
            with urlopen(req, timeout=timeout) as resp:
                data = resp.read()
                return json_mod.loads(data) if data else {}
        except HTTPError as e:
            if e.code == 401:
                raise AuthError("Unauthorized: invalid or expired token") from e
            if e.code == 403:
                raise AuthError("Forbidden: insufficient permissions") from e
            if e.code == 404:
                raise ManagedServiceError(f"Not found: {path}") from e
            if e.code == 409:
                try:
                    msg = json_mod.loads(e.read()).get("error", str(e))
                except Exception:
                    msg = str(e)
                raise TableError(msg) from e
            try:
                body = json_mod.loads(e.read()).get("error", str(e))
            except Exception:
                body = str(e)
            raise ManagedServiceError(f"API request failed: HTTP {e.code}: {body}") from e
        except URLError as e:
            raise ManagedServiceError(f"API request failed: {e}") from e

    def _get_root_path(self) -> str:
        """Get the base storage path for this workspace.

        Calls ``GET /workspaces/{id}/storage-path``.

        The returned path already includes the org_id and workspace_id,
        so dataset paths are: ``{root_path}/{table_name}``.
        """
        if self._root_path is not None:
            return self._root_path

        resp = self._api_request(
            "GET", f"/workspaces/{self.workspace_id}/storage-path"
        )
        path = resp.get("storage_path")
        if not path:
            raise WorkspaceError(
                f"No storage path returned for workspace '{self.workspace_id}'"
            )
        self._root_path = path
        logger.info("Storage path from API: %s", path)
        return self._root_path

    def _get_dataset_path(self, table_name: str) -> str:
        """Get full dataset path for a table.

        When the storage path comes from the API
        (``GET /workspaces/{id}/storage-path``), it already contains
        ``{bucket}/{org_id}/{workspace_id}``, so we only append the
        table name.
        """
        root_path = self._get_root_path().rstrip("/")
        # API storage-path already ends with /{workspace_id}
        if root_path.endswith(f"/{self.workspace_id}"):
            return f"{root_path}/{table_name}"
        return f"{root_path}/{self.workspace_id}/{table_name}"

    def _get_storage_creds(self, mode: str = "readwrite") -> Dict[str, str]:
        """Fetch temporary AWS credentials for S3 storage access.

        Calls ``POST /workspaces/{id}/credentials/generate`` with the
        requested *mode* (``read``, ``write``, or ``readwrite``).

        Returns a dict with ``aws_access_key_id``, ``aws_secret_access_key``,
        and ``aws_session_token``.
        """
        resp = self._api_request(
            "POST",
            f"/workspaces/{self.workspace_id}/credentials/generate",
            json_data={"mode": mode},
        )
        creds = resp.get("creds", resp)
        return creds

    def _apply_storage_creds(self, mode: str = "readwrite") -> None:
        """Fetch storage credentials and set them as environment variables.

        This allows ``deeplake.create()``/``deeplake.open()`` to access S3
        without requiring the user to set AWS env vars manually.
        """
        creds = self._get_storage_creds(mode)
        if creds.get("aws_access_key_id"):
            os.environ["AWS_ACCESS_KEY_ID"] = creds["aws_access_key_id"]
            os.environ["AWS_SECRET_ACCESS_KEY"] = creds["aws_secret_access_key"]
            os.environ["AWS_SESSION_TOKEN"] = creds.get("aws_session_token", "")
            logger.info("Applied storage credentials to environment")

    # ------------------------------------------------------------------
    # Unified ingest pipeline: source -> normalize -> write -> commit
    # ------------------------------------------------------------------

    def ingest(
        self,
        table_name: str,
        data: Optional[Dict[str, Any]] = None,
        *,
        format: Optional[Any] = None,
        schema: Optional[Dict[str, str]] = None,
        index: Optional[List[str]] = None,
        on_progress: Optional[Callable[[int, int], None]] = None,
        chunk_size: int = 1000,
        chunk_overlap: int = 200,
        pdf_dpi: int = 150,
    ) -> Dict[str, Any]:
        """Ingest data into a managed table.

        Creates the table if it does not exist, or **appends** to an
        existing table.  Safe to call multiple times — the table
        schema must be compatible with the new data.

        Thread safety: the C++ deeplake operations (open, append,
        commit) are serialized via a per-client lock.  Multiple
        threads sharing the same ``Client`` instance will not
        segfault, but will serialize their writes.

        Args:
            table_name: Name for the table.
            data: Data to ingest as a dict.  Required unless *format* is
                provided.  Processing depends on content:
                - ``{"_huggingface": "dataset_name"}`` loads from HuggingFace.
                - When *schema* marks columns as ``"FILE"``, those columns
                  are treated as file paths and processed (chunked, etc.).
                - Otherwise, ``{col: [values]}`` is ingested directly.
            format: Optional format object with a ``normalize()`` method
                that yields ``dict[str, list]`` batches.  When provided,
                *data* is ignored and the format object drives ingestion.
                See :class:`deeplake.managed.formats.CocoPanoptic` for an
                example.
            schema: Optional schema override {column_name: type_name}.
                Use ``"FILE"`` as the type for columns containing file paths.
            index: Optional list of column names to create
                ``deeplake_index`` on after ingestion.  Suitable for
                EMBEDDING columns (vector similarity search) and TEXT
                columns (BM25 text search).
            on_progress: Progress callback(rows_written, total).
            chunk_size: Text chunk size in characters (default 1000).
            chunk_overlap: Text chunk overlap in characters (default 200).
            pdf_dpi: DPI for PDF page rendering (default 150).
                Higher values produce sharper images but are slower.
                300 DPI is ~3.5× slower than 150 DPI.

        Returns:
            Dict with table_name, row_count, dataset_path.

        Example:
            >>> client.ingest("videos", {"path": ["v1.mp4"]}, schema={"path": "FILE"})
            >>> client.ingest("docs", {"text": ["a", "b"]})
            >>> client.ingest("cifar", {"_huggingface": "cifar10"})
            >>> client.ingest("embeddings", {
            ...     "text": ["hello", "world"],
            ...     "embedding": [[0.1, 0.2], [0.3, 0.4]],
            ... }, index=["embedding", "text"])
        """
        if format is None and data is None:
            raise IngestError("Either data or format must be provided.")
        if data is not None and not isinstance(data, dict):
            raise IngestError(f"data must be a dict, got {type(data).__name__}.")
        if data is not None and not data and format is None:
            raise IngestError("data must not be empty.")

        # al:// path for this table — used by the C++ backend to resolve
        # credentials via GET /api/org/{workspace}/ds/{table}/creds
        al_path = f"al://{self.workspace_id}/{table_name}"
        logger.info("Ingesting to table: %s (%s)", table_name, al_path)

        try:
            import deeplake
        except ImportError:
            raise ManagedServiceError(
                "deeplake package required. Install with: pip install deeplake"
            )

        try:
            # Enable parallel storage I/O (S3/GCS chunk uploads)
            try:
                if hasattr(deeplake, "storage") and hasattr(deeplake.storage, "set_concurrency"):
                    deeplake.storage.set_concurrency(32)
            except Exception:
                pass  # Non-critical; fall back to default concurrency

            # Dispatch based on format object or data content
            if format is not None:
                if not hasattr(format, "normalize"):
                    raise IngestError(
                        "format object must have a normalize() method."
                    )
                # Merge format-provided schema hints with user schema
                if hasattr(format, "schema") and callable(format.schema):
                    fmt_schema = format.schema()
                    if fmt_schema:
                        schema = {**fmt_schema, **(schema or {})}
                batches = format.normalize()
            elif "_huggingface" in data:
                dataset_name = data["_huggingface"]
                if not isinstance(dataset_name, str):
                    raise IngestError(
                        f"_huggingface value must be a string, got {type(dataset_name).__name__}."
                    )
                batches = self._normalize_huggingface(dataset_name)
            elif schema and any(v.upper() == "FILE" for v in schema.values()):
                file_columns = [c for c, t in schema.items() if t.upper() == "FILE"]
                all_files = []
                for col in file_columns:
                    if col not in data:
                        raise IngestError(
                            f"Schema declares '{col}' as FILE but column not in data."
                        )
                    all_files.extend(data[col])
                if not all_files:
                    raise IngestError("FILE columns contain no file paths.")
                batches = self._normalize_files(all_files, chunk_size, chunk_overlap, pdf_dpi=pdf_dpi)
            elif schema and any(v.upper() == "VIDEO" for v in schema.values()):
                # VIDEO columns: read file bytes and pass directly to the C++
                # backend which stores them as DLREF references.  No chunking
                # or normalization — the video is stored as-is.
                video_columns = [c for c, t in schema.items() if t.upper() == "VIDEO"]
                resolved = dict(data)
                for col in video_columns:
                    if col not in resolved:
                        raise IngestError(
                            f"Schema declares '{col}' as VIDEO but column not in data."
                        )
                    paths = resolved[col]
                    resolved[col] = []
                    for p in paths:
                        if isinstance(p, bytes):
                            resolved[col].append(p)
                        elif isinstance(p, str) and os.path.isfile(p):
                            with open(p, "rb") as fh:
                                resolved[col].append(fh.read())
                        else:
                            raise IngestError(
                                f"VIDEO column '{col}': expected file path or bytes, got {type(p).__name__}"
                            )
                batches = self._normalize_dict(resolved)
            else:
                batches = self._normalize_dict(data)

            # Peek at the first batch to determine schema, then create the
            # table via the API.  The API call
            # (POST /workspaces/{id}/tables with table_schema) creates both
            # the PostgreSQL table and the S3 dataset via pg_deeplake.
            first_batch, batches = self._peek_first_batch(batches)

            # Sort columns alphabetically — pg_deeplake's DuckDB scanner
            # expects deeplake dataset columns to match the PG table column
            # order, and the API sorts table_schema keys alphabetically.
            first_batch = dict(sorted(first_batch.items()))

            pg_schema = self._build_pg_schema(first_batch, schema, format)

            # Create table via API — pg_deeplake creates both the PG table
            # and the S3 dataset in one shot.
            table_created = self._create_table_via_api(table_name, al_path, pg_schema)

            # Detect IMAGE columns for inline thumbnail generation
            image_cols = self._detect_image_columns(
                pg_schema, format, first_batch,
            )

            # Re-chain the peeked batch with the remaining batches
            import itertools
            all_batches = itertools.chain([first_batch], batches)

            # Formats with variable-shape arrays (e.g. COCO masks/boxes
            # with different N annotations per image) need flush_every=1
            # to avoid batching variable-shape arrays together.
            flush = 1 if (format is not None and hasattr(format, 'flush_every')) else 200
            if hasattr(format, 'flush_every'):
                flush = format.flush_every

            # Hold a lock while touching global deeplake.client.endpoint
            # and performing C++ dataset operations (open/append/commit)
            # to prevent concurrent threads from clobbering state.
            with self._deeplake_lock:
                deeplake.client.endpoint = self.api_url
                ds = deeplake.open(al_path, token=self.token)

                try:
                    row_count = self._write_batches(
                        ds, all_batches, schema, on_progress,
                        image_cols=image_cols,
                        flush_every=flush,
                        format=format,
                    )

                    # Final commit for any rows written after the last periodic commit
                    ds.commit()
                except Exception:
                    # Clean up: drop the table if we created it during this
                    # call, so the user doesn't see an empty table.
                    if table_created:
                        try:
                            self.drop_table(table_name)
                        except Exception:
                            pass  # Best-effort cleanup
                    raise
                finally:
                    del ds

            # Create indexes on requested columns (outside the lock —
            # these are API calls, not C++ operations)
            if index:
                for col_name in index:
                    try:
                        self.create_index(table_name, col_name)
                    except Exception as idx_err:
                        logger.warning(
                            "Failed to create index on %s.%s: %s",
                            table_name, col_name, idx_err,
                        )

            return {
                "table_name": table_name,
                "row_count": row_count,
                "dataset_path": al_path,
            }

        except Exception as e:
            if isinstance(e, (IngestError, ManagedServiceError)):
                raise
            raise IngestError(f"Failed to ingest data: {e}") from e

    # ------------------------------------------------------------------
    # Schema helpers for API-driven table creation
    # ------------------------------------------------------------------

    @staticmethod
    def _peek_first_batch(batches):
        """Consume the first batch from *batches* and return it separately.

        Returns ``(first_batch, remaining_iterator)``.
        """
        it = iter(batches)
        first = next(it)
        return first, it

    # Mapping from deeplake / SDK schema names to PostgreSQL type names
    # expected by ``POST /workspaces/{id}/tables``.
    _SCHEMA_TO_PG: Dict[str, str] = {
        "TEXT": "TEXT",
        "JSON": "JSONB",
        "JSONB": "JSONB",
        "INT": "BIGINT",
        "INT32": "INTEGER",
        "INT64": "BIGINT",
        "FLOAT": "DOUBLE PRECISION",
        "FLOAT32": "REAL",
        "FLOAT64": "DOUBLE PRECISION",
        "BOOL": "BOOLEAN",
        "BINARY": "BYTEA",
        "IMAGE": "IMAGE",
        "VIDEO": "VIDEO",
        "EMBEDDING": "float4[]",
        "SEGMENT_MASK": "SEGMENT_MASK",
        "BINARY_MASK": "BINARY_MASK",
        "BOUNDING_BOX": "BOUNDING_BOX",
        "CLASS_LABEL": "CLASS_LABEL",
        "POLYGON": "DEEPLAKE_POLYGON",
        "POINT": "DEEPLAKE_POINT",
        "MESH": "MESH",
        "MEDICAL": "MEDICAL",
    }

    def _build_pg_schema(
        self,
        batch: Dict[str, list],
        schema: Optional[Dict[str, str]],
        format: Optional[Any],
    ) -> Dict[str, str]:
        """Derive a ``{column: SQL_TYPE}`` mapping for the API's ``table_schema``.

        Considers, in priority order:
        1. Explicit *schema* passed by the user.
        2. Type inference from the first batch's values.
        3. ``format.pg_schema()`` overrides — domain types like IMAGE,
           SEGMENT_MASK replace the inferred BYTEA types.
        """
        pg_schema: Dict[str, str] = {}

        try:
            import numpy as _np
            _has_numpy = True
        except ImportError:
            _has_numpy = False

        for col_name, values in batch.items():
            # Explicit schema
            if schema and col_name in schema:
                type_name = schema[col_name].upper()
                if type_name == "FILE":
                    continue
                pg_schema[col_name] = self._SCHEMA_TO_PG.get(type_name, "TEXT")
                continue

            # Infer from first value
            sample = values[0] if isinstance(values, list) and values else values

            # Check for numpy arrays first (before scalar checks, since
            # numpy scalars pass isinstance(x, (int, float)) checks).
            if _has_numpy and isinstance(sample, _np.ndarray):
                if sample.ndim == 1 and _np.issubdtype(sample.dtype, _np.number):
                    pg_schema[col_name] = "float4[]"
                elif sample.ndim == 2 and _np.issubdtype(sample.dtype, _np.number):
                    pg_schema[col_name] = "float4[][]"
                else:
                    pg_schema[col_name] = "BYTEA"
            elif isinstance(sample, bool):
                pg_schema[col_name] = "BOOLEAN"
            elif isinstance(sample, int):
                pg_schema[col_name] = "BIGINT"
            elif isinstance(sample, float):
                pg_schema[col_name] = "DOUBLE PRECISION"
            elif isinstance(sample, bytes):
                pg_schema[col_name] = "BYTEA"
            elif isinstance(sample, (list, tuple)):
                # Check if it's a flat list of numbers (embedding)
                if sample and all(isinstance(x, (int, float)) for x in sample):
                    pg_schema[col_name] = "float4[]"
                # Check if it's a list of lists of numbers (bag of embeddings)
                elif sample and all(
                    isinstance(x, (list, tuple)) and x and all(
                        isinstance(v, (int, float)) for v in x
                    )
                    for x in sample
                ):
                    pg_schema[col_name] = "float4[][]"
                else:
                    pg_schema[col_name] = "TEXT"
            elif isinstance(sample, str):
                # Detect JSON strings → JSONB for queryability in PG
                stripped = sample.lstrip()
                if stripped and stripped[0] in ('[', '{'):
                    pg_schema[col_name] = "JSONB"
                else:
                    pg_schema[col_name] = "TEXT"
            else:
                pg_schema[col_name] = "TEXT"

        # Apply format's pg_schema() domain type overrides (e.g. IMAGE,
        # SEGMENT_MASK).  These replace the inferred types so that the
        # API creates the table with the correct domain types directly.
        if format is not None and hasattr(format, 'pg_schema'):
            for col_name, domain_type in format.pg_schema().items():
                if col_name in pg_schema:
                    pg_schema[col_name] = domain_type

        # Remove columns that the format wants excluded from the PG table
        # (e.g. variable-shape arrays that need special deeplake types).
        if format is not None and hasattr(format, 'pg_exclude_columns'):
            for col_name in format.pg_exclude_columns():
                pg_schema.pop(col_name, None)

        # Add _thumbnail columns for each IMAGE column.  Thumbnails are
        # stored inline in the same table (128×128 JPEG) rather than in
        # a separate thumbnails table.  Use BYTEA (not IMAGE domain)
        # since thumbnails are derived data, not primary images.
        image_cols = self._detect_image_columns(pg_schema, format, batch)
        for col_name in image_cols:
            thumb_col = f"{col_name}_thumbnail"
            if thumb_col not in pg_schema:
                pg_schema[thumb_col] = "IMAGE"

        return pg_schema

    @staticmethod
    def _detect_image_columns(
        pg_schema: Dict[str, str],
        format: Optional[Any],
        batch: Dict[str, list],
    ) -> List[str]:
        """Detect which columns contain IMAGE data for inline thumbnails.

        Sources (in priority order):
        1. format.image_columns() — explicit declaration from a Format.
        2. format.pg_schema() — columns with type "IMAGE".
        3. pg_schema — columns whose PG type is "IMAGE".
        4. Auto-detect: a column named "image" with bytes data.
        """
        # 1. Format declares image_columns explicitly
        if format is not None and hasattr(format, "image_columns"):
            try:
                cols = format.image_columns()
                if cols:
                    return cols
            except Exception:
                pass

        # 2. Format pg_schema declares IMAGE type
        if format is not None and hasattr(format, "pg_schema"):
            try:
                pg = format.pg_schema()
                cols = [c for c, t in pg.items() if t.upper() == "IMAGE"]
                if cols:
                    return cols
            except Exception:
                pass

        # 3. PG schema has IMAGE columns
        cols = [c for c, t in pg_schema.items() if t.upper() == "IMAGE"]
        if cols:
            return cols

        # 4. Auto-detect: column named "image" with bytes data
        if "image" in batch:
            sample = batch["image"]
            if isinstance(sample, list) and sample:
                sample = sample[0]
            if isinstance(sample, bytes):
                return ["image"]

        return []

    _THUMBNAIL_SIZE = (128, 128)

    @staticmethod
    def _generate_inline_thumbnails(
        buffer: Dict[str, list],
        image_cols: List[str],
    ) -> None:
        """Generate 128×128 thumbnails for IMAGE columns and add them
        as ``{col}_thumbnail`` columns directly into the buffer.

        Modifies *buffer* in-place.  Thumbnail generation is best-effort:
        rows where decoding fails get an empty bytes placeholder so that
        column lengths stay consistent.

        Images are processed in parallel (4 threads) since PIL releases
        the GIL during decode/encode.
        """
        try:
            from PIL import Image as PILImage
        except ImportError:
            return

        import io
        from concurrent.futures import ThreadPoolExecutor

        def _make_thumbnail(val):
            try:
                if isinstance(val, bytes):
                    raw = val
                elif hasattr(val, "numpy"):
                    raw = bytes(val.numpy())
                else:
                    raw = bytes(val)

                if not raw:
                    return b""

                img = PILImage.open(io.BytesIO(raw))
                thumb = img.copy()
                thumb.thumbnail((128, 128), PILImage.LANCZOS)
                if thumb.mode in ("RGBA", "P"):
                    thumb = thumb.convert("RGB")
                buf = io.BytesIO()
                thumb.save(buf, format="JPEG", quality=85)
                return buf.getvalue()
            except Exception:
                return b""

        for col in image_cols:
            if col not in buffer:
                continue

            thumb_col = f"{col}_thumbnail"
            values = buffer[col]

            with ThreadPoolExecutor(max_workers=4) as executor:
                buffer[thumb_col] = list(executor.map(_make_thumbnail, values))

    def _write_batches(
        self,
        ds,
        batches,
        schema,
        on_progress=None,
        image_cols=None,
        flush_every: int = 200,
        commit_every: int = 2000,
        format=None,
    ):
        """Write normalized batches to dataset with buffering.

        Accumulates rows from normalizer generators into larger batches
        before calling ds.append(), reducing per-call overhead.  Commits
        periodically so that memory is bounded and partial progress
        survives crashes.

        Args:
            ds: DeepLake dataset handle.
            batches: Generator of dict[str, list] batches (may be 1-row each).
            schema: Optional explicit schema mapping.
            on_progress: Progress callback(rows_written, total).
            image_cols: List of IMAGE column names for inline thumbnail
                generation.  When non-empty, a ``{col}_thumbnail`` column
                (128×128 JPEG) is added to each buffer before flushing.
            flush_every: Rows to buffer before calling ds.append().
            commit_every: Rows between ds.commit() calls.
        """
        if image_cols is None:
            image_cols = []

        row_count = 0
        buffer: Dict[str, list] = {}
        buffer_rows = 0
        columns_ensured = False
        rows_since_commit = 0

        for batch in batches:
            if not batch:
                continue
            first_col = next(iter(batch.values()))
            if isinstance(first_col, list) and len(first_col) == 0:
                continue

            batch_rows = len(first_col) if isinstance(first_col, list) else 1

            # Merge batch into buffer
            for col, values in batch.items():
                buf_col = buffer.get(col)
                if buf_col is None:
                    buffer[col] = list(values) if isinstance(values, list) else [values]
                else:
                    if isinstance(values, list):
                        buf_col.extend(values)
                    else:
                        buf_col.append(values)
            buffer_rows += batch_rows

            # Flush buffer when large enough
            if buffer_rows >= flush_every:
                # Generate inline thumbnails before flushing
                if image_cols:
                    self._generate_inline_thumbnails(buffer, image_cols)

                if not columns_ensured:
                    self._ensure_columns(ds, buffer, schema, format=format)
                    columns_ensured = True
                self._append_buffer(ds, buffer, buffer_rows)
                row_count += buffer_rows
                rows_since_commit += buffer_rows
                buffer = {}
                buffer_rows = 0

                if on_progress:
                    on_progress(row_count, -1)

                # Periodic commit to free C++ buffers and enable crash recovery
                if rows_since_commit >= commit_every:
                    ds.commit()
                    rows_since_commit = 0
                    logger.info("Committed %d rows so far", row_count)

        # Flush remaining rows
        if buffer_rows > 0:
            if image_cols:
                self._generate_inline_thumbnails(buffer, image_cols)

            if not columns_ensured:
                self._ensure_columns(ds, buffer, schema)
            self._append_buffer(ds, buffer, buffer_rows)
            row_count += buffer_rows

            if on_progress:
                on_progress(row_count, -1)

        return row_count

    @staticmethod
    def _append_buffer(ds, buffer, buffer_rows):
        """Append buffer to dataset, falling back to row-by-row for variable-shape data."""
        try:
            ds.append(buffer)
        except Exception:
            # Variable-shape arrays (e.g. COCO masks/boxes with different N per image)
            # can't be stacked into a single batch.  Fall back to row-by-row append.
            cols = list(buffer.keys())
            for i in range(buffer_rows):
                row = {col: [buffer[col][i]] for col in cols}
                ds.append(row)

    def _ensure_columns(self, ds, batch, schema, format=None):
        """Ensure dataset has all columns needed for a batch.

        Uses explicit schema if provided, otherwise infers types from values.
        If *format* has a ``deeplake_types()`` method, those types take
        precedence for the columns they declare.
        """
        from deeplake import types

        # Format-declared types take highest priority
        format_types = {}
        if format is not None and hasattr(format, 'deeplake_types'):
            format_types = format.deeplake_types()

        type_map = {
            "TEXT": types.Text,
            "INT": types.Int64,
            "INT32": types.Int32,
            "INT64": types.Int64,
            "FLOAT": types.Float64,
            "FLOAT32": types.Float32,
            "FLOAT64": types.Float64,
            "BOOL": types.Bool,
            "BINARY": types.Bytes,
            "IMAGE": types.Image,
            "VIDEO": types.Bytes,
            "EMBEDDING": lambda: types.Embedding(size=768),
            "SEGMENT_MASK": types.SegmentMask,
            "BINARY_MASK": lambda: types.BinaryMask(sample_compression="lz4"),
            "BOUNDING_BOX": lambda: types.BoundingBox(types.Float32(), "LTWH", "pixel"),
            "CLASS_LABEL": lambda: types.ClassLabel(types.Array("uint32", 1)),
            "POLYGON": types.Polygon,
            "POINT": types.Point,
            "MESH": types.Mesh,
            "MEDICAL": lambda: types.Medical("dcm"),
        }

        existing = {c.name for c in ds.schema.columns}

        try:
            import numpy as _np
            _has_np = True
        except ImportError:
            _has_np = False

        for col_name, values in batch.items():
            if col_name in existing:
                continue

            # Format-declared deeplake types take highest priority
            if col_name in format_types:
                dtype = format_types[col_name]
                ds.add_column(col_name, dtype() if callable(dtype) else dtype)
                existing.add(col_name)
                continue

            if schema and col_name in schema:
                type_name = schema[col_name].upper()
                if type_name == "FILE":
                    continue
                if type_name in type_map:
                    dtype = type_map[type_name]
                    ds.add_column(col_name, dtype() if callable(dtype) else dtype)
                else:
                    ds.add_column(col_name, types.Text())
            else:
                # Infer from first value
                sample = values[0] if isinstance(values, list) and values else values

                if _has_np and isinstance(sample, _np.ndarray):
                    if sample.ndim == 1 and _np.issubdtype(sample.dtype, _np.number):
                        ds.add_column(col_name, types.Embedding(size=sample.shape[0]))
                    elif sample.ndim == 2 and _np.issubdtype(sample.dtype, _np.number):
                        ds.add_column(col_name, types.Array("float32", dimensions=2))
                    else:
                        ds.add_column(col_name, types.Bytes())
                elif isinstance(sample, bool):
                    ds.add_column(col_name, types.Bool())
                elif isinstance(sample, int):
                    ds.add_column(col_name, types.Int64())
                elif isinstance(sample, float):
                    ds.add_column(col_name, types.Float64())
                elif isinstance(sample, bytes):
                    ds.add_column(col_name, types.Bytes())
                elif isinstance(sample, (list, tuple)):
                    if sample and all(isinstance(x, (int, float)) for x in sample):
                        ds.add_column(col_name, types.Embedding(size=len(sample)))
                    elif sample and all(
                        isinstance(x, (list, tuple)) and x and all(
                            isinstance(v, (int, float)) for v in x
                        )
                        for x in sample
                    ):
                        ds.add_column(col_name, types.Array("float32", dimensions=2))
                    else:
                        ds.add_column(col_name, types.Text())
                else:
                    ds.add_column(col_name, types.Text())

            existing.add(col_name)

    # ------------------------------------------------------------------
    # Normalizers: pure data transforms, no deeplake dependency
    # ------------------------------------------------------------------

    def _normalize_one_file(self, file_path, chunk_size, chunk_overlap, pdf_dpi=150):
        """Normalize a single file, returning a list of batch dicts."""
        path = Path(file_path)
        if not path.exists():
            raise IngestError(f"File not found: {file_path}")

        ext = path.suffix.lower()

        if ext in _VIDEO_EXTS:
            return list(self._normalize_video(path))
        elif ext in _IMAGE_EXTS:
            return [self._normalize_image(path)]
        elif ext == ".pdf":
            return list(self._normalize_pdf(path, dpi=pdf_dpi))
        elif ext in _TEXT_EXTS:
            return [self._normalize_text(path, chunk_size, chunk_overlap)]
        else:
            return [self._normalize_binary(path)]

    def _normalize_files(self, files, chunk_size, chunk_overlap, pdf_dpi=150):
        """Normalize file list into batches, processing files in parallel.

        Uses a thread pool to normalize multiple files concurrently.
        ffmpeg (video), PyMuPDF (PDF), and file I/O all release the GIL,
        so threads provide real parallelism for these workloads.
        """
        from concurrent.futures import ThreadPoolExecutor, as_completed

        max_workers = min(4, len(files)) if len(files) > 1 else 1

        if max_workers <= 1:
            # Single file or sequential fallback
            for file_path in files:
                yield from self._normalize_one_file(
                    file_path, chunk_size, chunk_overlap, pdf_dpi=pdf_dpi
                )
            return

        with ThreadPoolExecutor(max_workers=max_workers) as pool:
            # Submit all files for parallel processing
            future_to_path = {
                pool.submit(
                    self._normalize_one_file, fp, chunk_size, chunk_overlap, pdf_dpi
                ): fp
                for fp in files
            }

            for future in as_completed(future_to_path):
                file_path = future_to_path[future]
                try:
                    batches = future.result()
                except Exception as e:
                    raise IngestError(
                        f"Failed to process {file_path}: {e}"
                    ) from e
                yield from batches

    def _normalize_video(self, path, chunk_interval=10):
        """Normalize video into segment batches.

        Yields dict[str, list] per segment. Uses its own default
        chunk_interval of 10 seconds (not the text chunk_size).
        """
        import subprocess
        import tempfile
        import json
        import uuid

        file_id = str(uuid.uuid4())

        # Probe video duration
        probe_cmd = [
            "ffprobe", "-v", "quiet", "-print_format", "json",
            "-show_format", str(path)
        ]
        try:
            result = subprocess.run(probe_cmd, capture_output=True, text=True, check=True)
            probe_data = json.loads(result.stdout)
            duration = float(probe_data.get("format", {}).get("duration", 0))
        except Exception as e:
            logger.warning("Failed to probe video %s: %s", path, e)
            duration = 0

        if duration <= 0:
            # Can't chunk, store whole file as single batch
            yield {
                "id": [f"{file_id}_0"],
                "file_id": [file_id],
                "chunk_index": [0],
                "start_time": [0.0],
                "end_time": [0.0],
                "video_data": [path.read_bytes()],
                "thumbnail": [None],
                "text": [f"Video: {path.name}"],
            }
            return

        # Chunk video
        import math
        num_chunks = math.ceil(duration / chunk_interval)

        for idx in range(num_chunks):
            start = idx * chunk_interval
            seg_duration = min(chunk_interval, duration - start)
            end = start + seg_duration

            # Use a per-segment temp dir so files are cleaned up immediately
            # after being read, instead of accumulating for the full video.
            with tempfile.TemporaryDirectory() as tmpdir:
                # Extract segment
                seg_path = Path(tmpdir) / f"seg_{idx}.mp4"
                cmd = [
                    "ffmpeg", "-y", "-ss", str(start), "-t", str(seg_duration),
                    "-i", str(path), "-c", "copy", str(seg_path)
                ]
                try:
                    subprocess.run(cmd, capture_output=True, check=True, timeout=300)
                except Exception as e:
                    logger.warning("Failed to extract segment %d: %s", idx, e)
                    continue

                # Extract thumbnail
                thumb_path = Path(tmpdir) / f"thumb_{idx}.jpg"
                thumb_cmd = [
                    "ffmpeg", "-y", "-ss", str((start + end) / 2),
                    "-i", str(path), "-vframes", "1", "-s", "320x180",
                    str(thumb_path)
                ]
                try:
                    subprocess.run(thumb_cmd, capture_output=True, timeout=30)
                    thumbnail = thumb_path.read_bytes() if thumb_path.exists() else None
                except Exception:
                    thumbnail = None

                yield {
                    "id": [f"{file_id}_{idx}"],
                    "file_id": [file_id],
                    "chunk_index": [idx],
                    "start_time": [round(start, 3)],
                    "end_time": [round(end, 3)],
                    "video_data": [seg_path.read_bytes() if seg_path.exists() else None],
                    "thumbnail": [thumbnail],
                    "text": [f"Video segment {idx}: {start:.1f}s - {end:.1f}s"],
                }

    def _normalize_image(self, path):
        """Normalize single image into a batch dict."""
        import uuid

        file_id = str(uuid.uuid4())
        return {
            "id": [f"{file_id}_0"],
            "file_id": [file_id],
            "image": [path.read_bytes()],
            "filename": [path.name],
            "text": [f"Image: {path.name}"],
        }

    def _normalize_pdf(self, path, dpi=150):
        """Normalize PDF into per-page batches.

        Yields dict[str, list] per page. Falls back to storing the
        whole PDF as binary if PyMuPDF (fitz) is not available.

        Args:
            path: Path to PDF file.
            dpi: Resolution for page rendering (default 150).
        """
        import uuid

        file_id = str(uuid.uuid4())

        try:
            import fitz  # PyMuPDF
        except ImportError:
            # Fallback: store whole PDF as binary
            yield {
                "id": [f"{file_id}_0"],
                "file_id": [file_id],
                "page_index": [0],
                "image": [path.read_bytes()],
                "text": [f"PDF: {path.name}"],
            }
            return

        doc = fitz.open(path)

        for page_idx in range(len(doc)):
            page = doc[page_idx]

            # Render page to image at specified DPI
            scale = dpi / 72
            mat = fitz.Matrix(scale, scale)
            pix = page.get_pixmap(matrix=mat)
            img_bytes = pix.tobytes("png")

            # Extract text
            text = page.get_text()

            yield {
                "id": [f"{file_id}_{page_idx}"],
                "file_id": [file_id],
                "page_index": [page_idx],
                "image": [img_bytes],
                "text": [text or f"PDF page {page_idx + 1}"],
            }

        doc.close()

    def _normalize_text(self, path, chunk_size, chunk_overlap):
        """Normalize text file into a single batch dict with all chunks."""
        import uuid

        file_id = str(uuid.uuid4())
        content = path.read_text(encoding="utf-8", errors="replace")
        chunks = self._chunk_text(content, chunk_size, chunk_overlap)

        return {
            "id": [f"{file_id}_{i}" for i in range(len(chunks))],
            "file_id": [file_id] * len(chunks),
            "chunk_index": list(range(len(chunks))),
            "text": chunks,
        }

    def _normalize_binary(self, path):
        """Normalize generic binary file into a batch dict."""
        import uuid

        file_id = str(uuid.uuid4())
        return {
            "id": [f"{file_id}_0"],
            "file_id": [file_id],
            "data": [path.read_bytes()],
            "filename": [path.name],
        }

    def _chunk_text(
        self, text: str, chunk_size: int, overlap: int
    ) -> List[str]:
        """Split text into chunks with overlap.

        Uses sentence-aware splitting (splits on . ? !).
        """
        if len(text) <= chunk_size:
            return [text] if text.strip() else []

        chunks = []
        start = 0

        while start < len(text):
            end = start + chunk_size

            if end >= len(text):
                chunks.append(text[start:].strip())
                break

            # Try to find sentence boundary
            search_start = max(start + chunk_size - 100, start)
            best_break = end

            for sep in [". ", "? ", "! ", "\n\n", "\n"]:
                pos = text.rfind(sep, search_start, end + 50)
                if pos > start:
                    best_break = pos + len(sep)
                    break

            chunk = text[start:best_break].strip()
            if chunk:
                chunks.append(chunk)

            # Move start forward, accounting for overlap
            new_start = best_break - overlap
            # Prevent infinite loop by ensuring we always move forward
            if new_start <= start:
                start = best_break
            else:
                start = new_start

        return chunks

    def _normalize_dict(self, data):
        """Normalize dict data into 1000-row batches.

        Yields dict[str, list] batches sliced from the input data.
        """
        first_col = next(iter(data.keys()))
        row_count = len(data[first_col])
        batch_size = 1000

        for i in range(0, row_count, batch_size):
            yield {
                col: values[i:i + batch_size]
                for col, values in data.items()
            }

    def _normalize_huggingface(self, dataset_name):
        """Normalize HuggingFace dataset into 100-row batches.

        Yields dict[str, list] batches streamed from the dataset.
        """
        try:
            from datasets import load_dataset
        except ImportError:
            raise ManagedServiceError(
                "datasets package required. Install with: pip install datasets"
            )

        hf_ds = load_dataset(dataset_name, split="train", streaming=True)

        # Stream and batch
        batch = []
        batch_size = 100

        for item in hf_ds:
            row = {}
            for col, val in item.items():
                if hasattr(val, "tobytes"):  # PIL Image
                    import io
                    buf = io.BytesIO()
                    val.save(buf, format="PNG")
                    row[col] = buf.getvalue()
                else:
                    row[col] = val
            batch.append(row)

            if len(batch) >= batch_size:
                yield {k: [d[k] for d in batch] for k in batch[0].keys()}
                batch = []

        # Flush remaining
        if batch:
            yield {k: [d[k] for d in batch] for k in batch[0].keys()}

    # ------------------------------------------------------------------
    # Table management via REST API
    # ------------------------------------------------------------------

    def _create_table_via_api(
        self,
        table_name: str,
        dataset_path: str,
        pg_schema: Optional[Dict[str, str]] = None,
    ) -> bool:
        """Create the table via the REST API.

        Calls ``POST /workspaces/{id}/tables`` which creates both the
        PostgreSQL table and the S3 dataset via pg_deeplake.

        Returns ``True`` if the table was newly created, ``False`` if it
        already existed.

        Raises TableError if creation fails (unless the table already exists).
        """
        try:
            body: Dict[str, Any] = {"table_name": table_name}
            if pg_schema:
                body["table_schema"] = pg_schema
            self._api_request(
                "POST",
                f"/workspaces/{self.workspace_id}/tables",
                json_data=body,
                timeout=120,
            )
            logger.info(
                "Created table %s (dataset: %s) via API",
                table_name,
                dataset_path,
            )
            return True
        except TableError as te:
            if "already exists" in str(te).lower():
                logger.info("Table %s already exists (ok)", table_name)
                return False
            else:
                raise

    def open_table(self, table_name: str):
        """Open a managed table as a deeplake Dataset.

        Returns a :class:`ManagedDataset` wrapper around the underlying
        ``deeplake.Dataset``.  The wrapper automatically calls ``refresh()``
        before every ``query()`` so that results always reflect the latest
        committed data — matching the behaviour of pg_deeplake, where each
        scan refreshes the dataset.

        The returned object supports the same interface as ``deeplake.Dataset``:
        - ds.pytorch(transform=fn) → torch.utils.data.Dataset
        - ds.tensorflow() → tf.data.Dataset
        - ds.batches(batch_size) → batch iterator
        - ds[idx] → row access with row.get_async("col") for prefetch

        Args:
            table_name: Name of the table (created via ingest()).

        Returns:
            ManagedDataset

        Example:
            >>> ds = client.open_table("videos")
            >>> loader = DataLoader(ds.pytorch(), batch_size=32, shuffle=True)
        """
        try:
            import deeplake
        except ImportError:
            raise ManagedServiceError(
                "deeplake package required. Install with: pip install deeplake"
            )

        deeplake.client.endpoint = self.api_url
        al_path = f"al://{self.workspace_id}/{table_name}"
        ds = deeplake.open(al_path, token=self.token)
        return ManagedDataset(ds)

    def create_index(
        self,
        table_name: str,
        column: str,
    ) -> None:
        """Create a ``deeplake_index`` on a column.

        Executes ``CREATE INDEX ... USING deeplake_index (column)`` via
        the query API.  Suitable for EMBEDDING columns (vector similarity
        search) and TEXT columns (BM25 text search).

        This is a no-op if the index already exists.

        Args:
            table_name: Name of the table.
            column: Column to index.

        Example:
            >>> client.create_index("embeddings", "embedding")
            >>> client.create_index("documents", "text")
        """
        safe_table = table_name.replace('"', '""')
        safe_col = column.replace('"', '""')
        idx_name = f"idx_{table_name}_{column}".replace('"', '""')
        sql = (
            f'CREATE INDEX IF NOT EXISTS "{idx_name}" '
            f'ON "{safe_table}" USING deeplake_index ("{safe_col}")'
        )
        try:
            self.query(sql)
            logger.info(
                "Created deeplake_index on %s(%s)", table_name, column,
            )
        except TableError as e:
            if "already exists" in str(e).lower():
                logger.info(
                    "Index on %s(%s) already exists (ok)",
                    table_name, column,
                )
            else:
                raise

    def query(
        self,
        sql: str,
        params: Optional[tuple] = None,
        timeout: int = 60,
    ) -> List[Dict[str, Any]]:
        """Execute SQL query via the API and return results.

        Calls ``POST /workspaces/{id}/tables/query``.

        Args:
            sql: SQL query string.
            params: Query parameters (for $1, $2, ... placeholders).
            timeout: HTTP request timeout in seconds (default 60).
                Increase for long-running queries such as large index
                builds or full-table aggregations.

        Returns:
            List of dictionaries, one per row.

        Example:
            >>> results = client.query("SELECT * FROM videos LIMIT 10")
            >>> results = client.query(
            ...     "SELECT * FROM videos WHERE id = $1",
            ...     ("video_123",)
            ... )
            >>> # Long-running query with extended timeout
            >>> results = client.query("SELECT COUNT(*) FROM big_table", timeout=300)
        """
        body: Dict[str, Any] = {"query": sql}
        if params:
            body["params"] = list(params)
        if timeout != 60:
            body["timeout_ms"] = timeout * 1000

        try:
            resp = self._api_request(
                "POST",
                f"/workspaces/{self.workspace_id}/tables/query",
                json_data=body,
                timeout=timeout,
            )
        except ManagedServiceError as e:
            raise TableError(f"Query failed: {e}") from e

        columns = resp.get("columns", [])
        rows = resp.get("rows") or []
        return [dict(zip(columns, row)) for row in rows]

    def list_tables(self) -> List[str]:
        """List all tables in the workspace.

        Calls ``GET /workspaces/{id}/tables``.
        """
        resp = self._api_request(
            "GET", f"/workspaces/{self.workspace_id}/tables"
        )
        tables = resp.get("tables", [])
        return [t["table_name"] for t in tables]

    def drop_table(self, table_name: str, if_exists: bool = True) -> None:
        """Drop a table from the workspace.

        Calls ``DELETE /workspaces/{id}/tables/{name}``.
        """
        try:
            self._api_request(
                "DELETE",
                f"/workspaces/{self.workspace_id}/tables/{table_name}",
            )
            logger.info("Dropped table %s via API", table_name)
        except ManagedServiceError as e:
            if if_exists and "not found" in str(e).lower():
                logger.info("Table %s does not exist (ok)", table_name)
                return
            raise


class ManagedQueryBuilder:
    """Chainable query builder for managed tables.

    Builds SQL and delegates execution to :meth:`Client.query`.

    Usage::

        results = (
            client.table("videos")
                .select("id", "text", "start_time")
                .where("file_id = $1", "abc")
                .where("start_time > $2", 60)
                .order_by("start_time")
                .limit(10)
        )()
    """

    def __init__(self, client: Client, table: str):
        self._client = client
        self._table = table
        self._columns: List[str] = ["*"]
        self._conditions: List[tuple] = []
        self._order_by_clauses: List[str] = []
        self._limit_val: Optional[int] = None
        self._offset_val: Optional[int] = None

    def select(self, *columns: str) -> "ManagedQueryBuilder":
        """Set columns to select. Default is ``'*'``."""
        self._columns = list(columns)
        return self

    def where(self, condition: str, *params: Any) -> "ManagedQueryBuilder":
        """Add a WHERE condition. Multiple calls are ANDed."""
        self._conditions.append((condition, params))
        return self

    def order_by(self, clause: str) -> "ManagedQueryBuilder":
        """Add ORDER BY clause, e.g. ``'start_time ASC'``."""
        self._order_by_clauses.append(clause)
        return self

    def limit(self, n: int) -> "ManagedQueryBuilder":
        """Set LIMIT."""
        self._limit_val = n
        return self

    def offset(self, n: int) -> "ManagedQueryBuilder":
        """Set OFFSET."""
        self._offset_val = n
        return self

    def _build_sql(self) -> Tuple[str, Optional[list]]:
        """Build SQL string and parameters list.

        Uses $1, $2, ... style placeholders for the API query endpoint.

        Returns:
            Tuple of ``(sql_string, params_list_or_none)``.
        """
        cols = ", ".join(self._columns)
        safe_table = self._table.replace('"', '""')
        parts = [f'SELECT {cols} FROM "{safe_table}"']

        params: List[Any] = []
        if self._conditions:
            where_clauses = []
            for cond, cond_params in self._conditions:
                where_clauses.append(cond)
                params.extend(cond_params)
            parts.append("WHERE " + " AND ".join(where_clauses))

        if self._order_by_clauses:
            parts.append("ORDER BY " + ", ".join(self._order_by_clauses))

        if self._limit_val is not None:
            parts.append(f"LIMIT {int(self._limit_val)}")

        if self._offset_val is not None:
            parts.append(f"OFFSET {int(self._offset_val)}")

        sql = " ".join(parts)
        return sql, params if params else None

    def execute(self) -> List[Dict[str, Any]]:
        """Execute query, return all results as a list of dicts."""
        sql, params = self._build_sql()
        return self._client.query(sql, tuple(params) if params else None)

    def __call__(self) -> List[Dict[str, Any]]:
        """Shorthand for ``execute()``."""
        return self.execute()

    def __repr__(self) -> str:
        sql, params = self._build_sql()
        return f"ManagedQueryBuilder(sql={sql!r}, params={params!r})"
